UPDATE eam.avdm_pact_concern SET concern_name = 'Application Resilience', layer = 'Application', description = 'Define fallback, retry, and graceful degradation strategy.', update_by = 'avdm_seed', update_at = now() WHERE concern_key = 'A6';
