    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    project_type_key VARCHAR NOT NULL,
    project_type_label VARCHAR NOT NULL,
    description text,
    typical_patterns jsonb NOT NULL DEFAULT '[]'::jsonb,
    typical_risks jsonb NOT NULL DEFAULT '[]'::jsonb,
    sort_order INTEGER NOT NULL DEFAULT 0,
    is_active BOOLEAN NOT NULL DEFAULT true,
    create_by VARCHAR NOT NULL DEFAULT 'system'::character varying,
    update_by VARCHAR NOT NULL DEFAULT 'system'::character varying,
    create_at TIMESTAMP NOT NULL DEFAULT now(),
    update_at TIMESTAMP NOT NULL DEFAULT now()
);

-- Table: eam.avdm_project_type_artifact_mapping
